var usersWithOrders = users
    .GroupJoin(orders,
        user => user.Id,
        order => order.UserId,
        (user, userOrders) => new
        {
            User = user,
            Orders = userOrders.ToList(),
            TotalSpent = userOrders.Sum(o => o.Total)
        })
    .ToList();
