            var userTask = scope.fork(() -> fetchUser(userId));
            var ordersTask = scope.fork(() -> fetchOrders(userId));

            scope.join();
            scope.throwIfFailed();

            return new User(userTask.get(), ordersTask.get());
        }
    }
