    data.iter().sum()
}

// Good - use Cow when needed
use std::borrow::Cow;

fn process<'a>(data: &'a str) -> Cow<'a, str> {
    if data.contains("bad") {
        Cow::Owned(data.replace("bad", "good"))
    } else {
        Cow::Borrowed(data)
    }
}
