## Common Patterns

### Builder Pattern
```rust
#[derive(Default)]
struct User {
    name: String,
    email: String,
    age: Option<u32>,
}

struct UserBuilder {
    user: User,
}

impl UserBuilder {
    fn new() -> Self {
        Self {
            user: User::default(),
        }
    }

    fn name(mut self, name: impl Into<String>) -> Self {
        self.user.name = name.into();
        self
    }

    fn email(mut self, email: impl Into<String>) -> Self {
        self.user.email = email.into();
        self
    }

    fn age(mut self, age: u32) -> Self {
        self.user.age = Some(age);
        self
    }

    fn build(self) -> User {
        self.user
    }
}

// Usage
