### RAII (Resource Acquisition Is Initialization)
```rust
struct File {
    handle: std::fs::File,
}

impl File {
    fn new(path: &str) -> std::io::Result<Self> {
        let handle = std::fs::File::open(path)?;
        Ok(Self { handle })
    }
}

impl Drop for File {
    fn drop(&mut self) {
        println!("Closing file");
        // File automatically closed
    }
}
